package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testGetHeaderWhenHeaderIsNull() throws Exception {
        // Create a new CSVFormat instance with header=null using reflection on a new instance
        CSVFormat format = CSVFormat.DEFAULT.withHeader("col1"); // create a non-default instance to modify

        Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);

        // CSVFormat is immutable, so we need to create a new instance with header=null via reflection
        // But since the header field is final, we must remove final modifier via reflection
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(headerField, headerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        headerField.set(format, null);

        String[] result = format.getHeader();
        assertNull(result);
    }

    @Test
    void testGetHeaderWhenHeaderIsNotNull() throws Exception {
        String[] headerValue = new String[]{"col1", "col2"};
        CSVFormat format = CSVFormat.DEFAULT.withHeader(headerValue);

        String[] result = format.getHeader();
        assertNotNull(result);
        assertArrayEquals(headerValue, result);
        assertNotSame(headerValue, result); // ensure clone returned, not original reference
    }
}
